// Prüfe Repair-Bedarf (V12_7 - runOnceForAllItems)
// Verwendet runOnceForAllItems um SplitInBatches-Kompatibilitätsprobleme zu vermeiden
const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { _repairNeeded: false, _repairSkipped: true, _repairSkipReason: 'kein Input' } }];
}

const rawItem = items[0];
const j = (rawItem && rawItem.json && typeof rawItem.json === 'object' && !Array.isArray(rawItem.json))
  ? rawItem.json
  : {};

if (!j.vorgangKey) {
  return [{ json: { ...j, _repairNeeded: false, _repairSkipped: true, _repairSkipReason: 'kein vorgangKey' } }];
}

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch(e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim());
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(s => String(s).trim()); } catch(e) {}
    return v.split(/\s*\|\s*/).filter(Boolean).map(s => String(s).trim());
  }
  return [];
}
function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') { const s = v.trim().toLowerCase(); return s === 'true' || s === '1'; }
  return false;
}

const analysis = parseObj(j.analysisJson);
const sl = parseObj(analysis.sourceLock || {});
const va = parseObj(analysis.visualAnchors || {});
const slValidFlag = robustBool(analysis.sourceLockValid);
const vaValidFlag = robustBool(analysis.visualAnchorsValid);

const slOk = !!(
  safeStr(sl.sourceTopic) &&
  safeStr(sl.sourceConflict) &&
  asArr(sl.requiredTerms).length >= 2 &&
  asArr(sl.requiredObjects).length >= 2 &&
  safeStr(sl.requiredAction) &&
  slValidFlag
);
const vaOk = !!(
  safeStr(va.satireThemaKonkret) &&
  safeStr(va.satireKonfliktKonkret) &&
  asArr(va.visualPflichtobjekte).length >= 2 &&
  safeStr(va.visualPflichthandlung) &&
  safeStr(va.visualErkennungssatz) &&
  safeStr(va.visualUeberzeichnung) &&
  asArr(va.visualVerboteneErsatzmotive).length >= 2 &&
  vaValidFlag
);

const needsVisual = robustBool(j.visualNeeded) || robustBool(j.instagramSharepicNoetig);
const sourceLockRepairNeeded = !slOk;
const visualAnchorRepairNeeded = needsVisual && !vaOk;
const repairNeeded = sourceLockRepairNeeded || visualAnchorRepairNeeded;

return [{ json: {
  ...j,
  _repairNeeded: repairNeeded,
  _repairSkipped: false,
  _sourceLockRepairNeeded: sourceLockRepairNeeded,
  _visualAnchorRepairNeeded: visualAnchorRepairNeeded,
  _repairReasonSL: !slOk ? 'sourceLock ungültig/unvollständig' : '',
  _repairReasonVA: !vaOk ? 'visualAnchors unvollständig' : '',
  _sourceLockCurrentlyValid: slOk,
  _visualAnchorsCurrentlyOk: vaOk
} }];

// n8n Code Node: "Normalisiere Bewertung + Visual Guard"
// Mode: Run Once for Each Item
// Liest die KI-Antwort von "AI Reparatur SourceLock+Anchors" und mergt sourceLock/visualAnchors
// in die Originaldaten aus "Prüfe Repair-Bedarf" (dieses Item ist die AI-Antwort, nicht die Row).

function getAiText(item) {
  try {
    const j = item.json || {};
    if (j.text && typeof j.text === 'string' && j.text.trim()) return j.text;
    const o = j.output;
    if (Array.isArray(o)) {
      for (let i = 0; i < o.length; i++) {
        const c = o[i].content;
        if (Array.isArray(c)) { for (let k = 0; k < c.length; k++) { if (c[k].text) return c[k].text; } }
      }
    }
    if (j.output_text) return j.output_text;
    if (j.message && j.message.content) return j.message.content;
    if (j.choices && j.choices[0] && j.choices[0].message) return j.choices[0].message.content || '';
    return '';
  } catch (e) { return ''; }
}

function extractJson(text) {
  if (!text) return null;
  const s = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const a = s.indexOf('{'), b = s.lastIndexOf('}');
  return (a === -1 || b === -1 || b <= a) ? null : s.slice(a, b + 1);
}

let input = {};
try {
  const ref = $('Prüfe Repair-Bedarf').item;
  if (ref && ref.json && typeof ref.json === 'object' && !Array.isArray(ref.json)) input = ref.json;
} catch (e) { input = {}; }

const rawAiText = getAiText($input.item);
const aiJsonStr = extractJson(rawAiText);
let repaired = {};
if (aiJsonStr) {
  try { repaired = JSON.parse(aiJsonStr) || {}; } catch (e) { repaired = {}; }
}

function safeStr(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function normText(v) {
  return safeStr(v)
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[„“”"'`´]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try {
      const p = JSON.parse(v);
      return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
    } catch (e) {}
  }
  return {};
}

function asArray(v) {
  if (Array.isArray(v)) {
    return v
      .filter(x => x !== null && x !== undefined && safeStr(x) !== '')
      .map(x => safeStr(x));
  }
  if (v === null || v === undefined || v === '') return [];
  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return [];
    try {
      const p = JSON.parse(t);
      if (Array.isArray(p)) return p.filter(Boolean).map(x => safeStr(x)).filter(Boolean);
    } catch (e) {}
    return t.split(/\s*\|\s*/).map(x => safeStr(x)).filter(Boolean);
  }
  return [safeStr(v)].filter(Boolean);
}

function hasValue(v) {
  if (Array.isArray(v)) return asArray(v).length > 0;
  if (v && typeof v === 'object') return Object.keys(v).length > 0;
  return safeStr(v).length > 0;
}

function pick(nestedValue, topValue, fallback = '') {
  return hasValue(nestedValue) ? nestedValue : (hasValue(topValue) ? topValue : fallback);
}

function num(v, fallback = 0) {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : fallback;
}

function enumValue(v, allowed, fallback) {
  const n = safeStr(v).toUpperCase();
  return allowed.includes(n) ? n : fallback;
}

function bool(v) {
  if (v === true || v === 1) return true;
  if (v === false || v === 0 || v === null || v === undefined) return false;
  const s = String(v).trim().toLowerCase();
  return ['true', '1', 'yes', 'ja', 'y'].includes(s);
}

function unique(arr) {
  const out = [];
  const seen = new Set();
  for (const x of asArray(arr)) {
    const k = normText(x);
    if (!k || seen.has(k)) continue;
    seen.add(k);
    out.push(x);
  }
  return out;
}

// Parse analysisJson, aber Top-Level-Felder weiter berücksichtigen.
const analysis = parseObj(input.analysisJson);

// KI-Reparaturantwort hat Vorrang vor der alten (fehlerhaften) Analyse.
if (repaired.sourceLock) analysis.sourceLock = repaired.sourceLock;
if (repaired.visualAnchors) analysis.visualAnchors = repaired.visualAnchors;

const nestedSL = parseObj(analysis.sourceLock || input.sourceLock);
const nestedVA = parseObj(analysis.visualAnchors || input.visualAnchors);

let sourceLock = {
  sourceTopic: safeStr(pick(nestedSL.sourceTopic, input.sourceTopic || analysis.sourceTopic)),
  sourceConflict: safeStr(pick(nestedSL.sourceConflict, input.sourceConflict || analysis.sourceConflict)),
  requiredTerms: unique(pick(nestedSL.requiredTerms, input.requiredTerms || analysis.requiredTerms, [])),
  requiredObjects: unique(pick(nestedSL.requiredObjects, input.requiredObjects || analysis.requiredObjects, [])),
  requiredAction: safeStr(pick(nestedSL.requiredAction, input.requiredAction || analysis.requiredAction)),
  affectedGroups: unique(pick(nestedSL.affectedGroups, input.affectedGroups || analysis.affectedGroups, [])),
  forbiddenDrift: unique(pick(nestedSL.forbiddenDrift, input.forbiddenDrift || analysis.forbiddenDrift, []))
};

let visualAnchors = {
  satireThemaKonkret: safeStr(pick(nestedVA.satireThemaKonkret, input.satireThemaKonkret || analysis.satireThemaKonkret)),
  satireKonfliktKonkret: safeStr(pick(nestedVA.satireKonfliktKonkret, input.satireKonfliktKonkret || analysis.satireKonfliktKonkret)),
  visualPflichtobjekte: unique(pick(nestedVA.visualPflichtobjekte, input.visualPflichtobjekte || analysis.visualPflichtobjekte, [])),
  visualPflichthandlung: safeStr(pick(nestedVA.visualPflichthandlung, input.visualPflichthandlung || analysis.visualPflichthandlung)),
  visualBetroffene: unique(pick(nestedVA.visualBetroffene, input.visualBetroffene || analysis.visualBetroffene, [])),
  visualOrt: safeStr(pick(nestedVA.visualOrt, input.visualOrt || analysis.visualOrt || '')),
  visualUeberzeichnung: safeStr(pick(nestedVA.visualUeberzeichnung, input.visualUeberzeichnung || analysis.visualUeberzeichnung)),
  visualErkennungssatz: safeStr(pick(nestedVA.visualErkennungssatz, input.visualErkennungssatz || analysis.visualErkennungssatz)),
  visualVerboteneErsatzmotive: unique(pick(nestedVA.visualVerboteneErsatzmotive, input.visualVerboteneErsatzmotive || analysis.visualVerboteneErsatzmotive, []))
};

const sourceStrictText = [
  input.title,
  input.vorgangsnummer,
  input.summaryText,
  input.thema,
  input.betroffene,
  input.kostenHaushalt,
  input.buergerwirkung,
  input.offenePunkte,
  input.unsicherheitenSummary,
  input.combinedText,
  input.analyseContext
].map(safeStr).join('\n');

const sourceNorm = normText(sourceStrictText);
const sourceWords = new Set(sourceNorm.split(' ').filter(w => w.length >= 3));

function sourceHasExactWord(term) {
  const n = normText(term);
  return n && !n.includes(' ') && sourceWords.has(n);
}

function sourceContainsPhrase(term) {
  const n = normText(term);
  return n.length >= 4 && sourceNorm.includes(n);
}

const realPartTerms = new Set([
  'finanzierung', 'haushalt', 'kosten', 'haushaltsreste', 'haushaltsrest',
  'massnahme', 'maßnahme', 'ort', 'gremium', 'sachobjekt', 'einrichtung',
  'lichtsignalanlage', 'signalgeber', 'bodenplatten', 'tasterkasten'
].map(normText));

const termObjectSet = new Set([
  ...sourceLock.requiredTerms,
  ...sourceLock.requiredObjects,
  sourceLock.requiredAction,
  visualAnchors.satireThemaKonkret,
  visualAnchors.visualOrt
].map(normText).filter(Boolean));

// forbiddenDrift darf echte Bestandteile nicht verbieten.
sourceLock.forbiddenDrift = unique(sourceLock.forbiddenDrift).filter(d => {
  const n = normText(d);
  if (!n) return false;
  if (realPartTerms.has(n)) return false;
  if (termObjectSet.has(n)) return false;
  if (sourceHasExactWord(d)) return false;
  return true;
});

// Bei Bildfreigabe mindestens drei echte Abdriftverbote ergänzen, falls nötig.
const fallbackDrift = [
  'allgemeine Rathaus-Satire ohne konkreten Vorgangsbezug',
  'allgemeiner Aktenberg als Hauptmotiv',
  'beliebiger Geldsack oder reine Finanzsymbolik als Hauptpointe',
  'Pointe auf Kosten schutzbedürftiger Betroffener',
  'Korruptionsunterstellung oder persönliche Schuldzuweisung'
];

for (const d of fallbackDrift) {
  if (sourceLock.forbiddenDrift.length >= 3) break;
  if (!sourceLock.forbiddenDrift.some(x => normText(x) === normText(d))) {
    sourceLock.forbiddenDrift.push(d);
  }
}

const sensitiveContextRe = /\b(minderjaehrig|minderjährig|kind|kinder|schueler|schüler|schuelerin|schülerin|behinder|barrierefrei|barrierefreiheit|blind|sehbehindert|taub|krank|pflege|rollstuhl|gefluecht|geflücht|wohnungslose|obdachlos|armut|opfer|notlage)\b/i;
const sensitiveContext = sensitiveContextRe.test(normText(sourceStrictText + ' ' + sourceLock.affectedGroups.join(' ')));

function isSensitivePersonObject(v) {
  const n = normText(v);
  if (!n) return false;

  // Sachobjekte mit Rollstuhl-/Barrierefreiheitsbezug bleiben erlaubt.
  if (/\b(rollstuhlrampe|rampe|barrierefreier zugang|barrierefreier taster|taster|signalgeber|bodenplatte|bodenplatten|leitstreifen|lichtsignalanlage)\b/.test(n)) {
    return false;
  }

  return /\b(blinder|blinde|sehbehinderter|sehbehinderte|behinderter|behinderte|mensch mit behinderung|menschen mit behinderung|schueler|schuelerin|schüler|schülerin|kind|kinder|minderjaehriger|minderjährige|patient|patientin|pflegebeduerftiger|pflegebedürftige|rollstuhlfahrer|gefluechteter|geflüchtete|wohnungslose|obdachlose|kranker|kranke)\b/.test(n);
}

const forbiddenSymbolRe = /\b(sparschwein|geldsack|waage|aktenberg|rathaus|nebel|monster|hai|haie|marionette|marionetten|theaterbuehne|theaterbühne|theater|clown|clowns|maskottchen)\b/;

function isForbiddenSymbol(v) {
  const n = normText(v);
  if (!n) return false;
  if (!forbiddenSymbolRe.test(n)) return false;

  // Nur erlauben, wenn das Symbol selbst belegbar Gegenstand der Vorlage ist.
  return !sourceContainsPhrase(v) && !sourceHasExactWord(v);
}

const genericObjectSet = new Set([
  'stadt', 'verwaltung', 'politik', 'buerokratie', 'bürokratie', 'gerechtigkeit',
  'haushalt', 'kosten', 'finanzierung', 'massnahme', 'maßnahme', 'verfahren',
  'gremium', 'beschluss', 'antrag', 'vorlage', 'thema', 'konflikt', 'situation',
  'problem', 'prioritaet', 'priorität', 'zustaendigkeit', 'zuständigkeit'
].map(normText));

function isConcreteObject(v) {
  const n = normText(v);
  if (!n || n.length < 3) return false;
  if (genericObjectSet.has(n)) return false;
  if (isForbiddenSymbol(v)) return false;
  if (sensitiveContext && isSensitivePersonObject(v)) return false;
  return true;
}

function concreteCount(arr) {
  return asArray(arr).filter(isConcreteObject).length;
}

function listForbiddenSymbols(arr) {
  return asArray(arr).filter(isForbiddenSymbol);
}

function listSensitiveObjects(arr) {
  return asArray(arr).filter(isSensitivePersonObject);
}

const visualText = [
  visualAnchors.visualUeberzeichnung,
  visualAnchors.visualErkennungssatz,
  analysis.visualMetaphor,
  analysis.satireBrief,
  analysis.satireAngle,
  asArray(analysis.satirePunchlines).join(' '),
  analysis.moeglicheSatirischeReaktion
].map(safeStr).join(' ');

const vNorm = normText(visualText);

function hasSensitiveMetaphor() {
  if (!sensitiveContext) return false;

  if (/\bblind(e|er|es|en)?\s+(augen|sparschwein|haushalt|verwaltung|planung|politik|ampel|stadt)\b/.test(vNorm)) return true;
  if (/\b(taub(e|er|es|en)?|lahm(e|er|es|en)?|krank(e|er|es|en)?|hilflos(e|er|es|en)?)\s+(verwaltung|planung|haushalt|politik|ampel|stadt)\b/.test(vNorm)) return true;
  if (/barrierefreiheit.{0,30}\b(luxus|spass|spaß|teurer spass|teurer spaß)\b/.test(vNorm)) return true;
  if (/\b(gefahrenszene|hilflosigkeit|panik|panisch|gefährdet|gefaehrdet|unfallopfer)\b/.test(vNorm)) return true;

  return false;
}

// Sensible sichtbare Betroffene vorsichtig leeren, aber nicht als Hauptfehler zählen.
let visualBetroffeneCleared = false;
if (sensitiveContext && visualAnchors.visualBetroffene.length > 0) {
  visualAnchors.visualBetroffene = [];
  visualBetroffeneCleared = true;
}

const sensitiveObjects = sensitiveContext ? [
  ...listSensitiveObjects(visualAnchors.visualPflichtobjekte),
  ...listSensitiveObjects(sourceLock.requiredObjects)
] : [];

const forbiddenSymbols = [
  ...listForbiddenSymbols(visualAnchors.visualPflichtobjekte),
  ...listForbiddenSymbols(sourceLock.requiredObjects)
];

const pflichtConcrete = concreteCount(visualAnchors.visualPflichtobjekte);
const reqObjConcrete = concreteCount(sourceLock.requiredObjects);

const sourceLockErrors = [];

if (!safeStr(sourceLock.sourceTopic)) sourceLockErrors.push('sourceLock.sourceTopic fehlt');
if (!safeStr(sourceLock.sourceConflict)) sourceLockErrors.push('sourceLock.sourceConflict fehlt');
if (asArray(sourceLock.requiredTerms).length < 2) sourceLockErrors.push('sourceLock.requiredTerms < 2');
if (reqObjConcrete < 2) sourceLockErrors.push('sourceLock.requiredObjects enthält weniger als 2 konkrete Objekte');
if (!safeStr(sourceLock.requiredAction)) sourceLockErrors.push('sourceLock.requiredAction fehlt');

const visualErrors = [];

if (!safeStr(visualAnchors.satireThemaKonkret)) visualErrors.push('satireThemaKonkret fehlt');
if (!safeStr(visualAnchors.satireKonfliktKonkret)) visualErrors.push('satireKonfliktKonkret fehlt');
if (pflichtConcrete < 2) visualErrors.push('visualPflichtobjekte enthält weniger als 2 konkrete Objekte');
if (!safeStr(visualAnchors.visualPflichthandlung)) visualErrors.push('visualPflichthandlung fehlt');
if (!safeStr(visualAnchors.visualErkennungssatz)) visualErrors.push('visualErkennungssatz fehlt');

const guardErrors = [];

if (sensitiveObjects.length > 0) {
  guardErrors.push('Sensible Betroffene als Pflichtobjekt/requiredObject erkannt: ' + sensitiveObjects.join(', '));
}

if (forbiddenSymbols.length > 0) {
  guardErrors.push('Symbol-Drift als Pflichtobjekt/requiredObject erkannt: ' + forbiddenSymbols.join(', '));
}

if (hasSensitiveMetaphor()) {
  guardErrors.push('Schutzlage wird als Metapher, Wortspiel oder Gefahrenszene verwendet');
}

if (visualBetroffeneCleared) {
  guardErrors.push('visualBetroffene bei sensiblem Thema geleert; Betroffene sind nicht Bildpointe');
}

const empfehlung = enumValue(analysis.empfehlung ?? input.empfehlung, ['IGNORIEREN', 'BEOBACHTEN', 'REAGIEREN'], 'BEOBACHTEN');
const sprengstoff = enumValue(analysis.sprengstoff ?? input.sprengstoff, ['KEINER', 'GERING', 'MITTEL', 'HOCH'], 'KEINER');
const ampelMap = { KEINER: '⚪', GERING: '🟡', MITTEL: '🟠', HOCH: '🔴' };
const ampel = ampelMap[sprengstoff] || '⚪';

const kommunikationspotenzial = num(analysis.kommunikationspotenzial ?? input.kommunikationspotenzial, 0);
const relevanz = num(analysis.relevanz ?? input.relevantScore ?? input.relevanz, 0);

let reaktionNoetig = bool(analysis.reaktionNoetig ?? input.reaktionNoetig);

if (empfehlung === 'REAGIEREN') reaktionNoetig = true;
if (empfehlung === 'IGNORIEREN') reaktionNoetig = false;

// SatireIntensity deterministisch an sprengstoff koppeln.
const maxIntensityBySprengstoff = { KEINER: 2, GERING: 2, MITTEL: 4, HOCH: 5 };
let satireIntensity = num(analysis.satireIntensity ?? input.satireIntensity, 0);

if (satireIntensity > 0) {
  satireIntensity = Math.max(1, Math.min(satireIntensity, maxIntensityBySprengstoff[sprengstoff] || 2));
}

const sourceLockValid = sourceLockErrors.length === 0;
const visualAnchorsValid = visualErrors.length === 0;
const blockedByGuard = guardErrors.some(e => !e.startsWith('visualBetroffene bei sensiblem Thema geleert'));
const guardValid = !blockedByGuard;

// Die "ist das ueberhaupt satirisch wert"-Entscheidung wird nicht hier neu getroffen,
// sondern kommt vom Eignungs-Agenten (P3), der einmalig pro Vorgang urteilt und sein
// Ergebnis in eignungsAgentJson persistiert. Dieser Reparatur-Workflow repariert nur
// SourceLock/VisualAnchors und wendet die deterministischen Gates erneut darauf an.
function parseObjLocal(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch (e) { return {}; }
}
const eignung = parseObjLocal(input.eignungsAgentJson);
const satireWorthIt = eignung.satireWorthIt === true;
const reservationsBlockImage = eignung.reservationsBlockImage === true;

const sharepicRecommended = satireWorthIt && sourceLockValid && visualAnchorsValid && guardValid && !reservationsBlockImage;
let instagramSharepicNoetig = sharepicRecommended;

const allErrors = [...sourceLockErrors, ...visualErrors, ...guardErrors];

let visualDecisionReason = '';
let sharepicNeedStageComputed = '';

if (!satireWorthIt) {
  sharepicNeedStageComputed = 'not_applicable';
  visualDecisionReason = 'Eignungs-Agent: ' + (safeStr(eignung.satireWorthItReason) || 'Kein Sharepic-Bedarf');
} else if (sharepicRecommended) {
  sharepicNeedStageComputed = 'topic_ok';
  visualDecisionReason = 'Sharepic freigegeben nach Reparatur: SourceLock und Visual-Anker vollstaendig, keine sensible Betroffenen-Pointe, keine Symbol-Drift.';
} else {
  sharepicNeedStageComputed = 'topic_error';
  const reasons = [...allErrors];
  if (reservationsBlockImage) reasons.push('Eignungs-Agent Bedenken: ' + (Array.isArray(eignung.reservations) ? eignung.reservations.join(' | ') : ''));
  visualDecisionReason = 'Sharepic weiterhin blockiert nach Reparatur: ' + reasons.join(' | ');
}

// Freigabe nur dort deterministisch korrigieren, wo es eindeutig ist.
const beweissicherheit = enumValue(analysis.beweissicherheit ?? input.beweissicherheit, ['NIEDRIG', 'MITTEL', 'HOCH'], 'NIEDRIG');
const rechtlichesRisiko = enumValue(analysis.rechtlichesRisiko ?? input.rechtlichesRisiko, ['NIEDRIG', 'MITTEL', 'HOCH'], 'NIEDRIG');

let freigabeEmpfohlen = bool(analysis.freigabeEmpfohlen ?? input.freigabeEmpfohlen);

if (empfehlung === 'REAGIEREN' && beweissicherheit !== 'NIEDRIG' && rechtlichesRisiko !== 'HOCH') {
  freigabeEmpfohlen = true;
}

if (rechtlichesRisiko === 'HOCH' || beweissicherheit === 'NIEDRIG') {
  freigabeEmpfohlen = false;
}

// Wenn P1 bereits contentJson/websiteHeadline erzeugt hat oder headlineChoiceStage/
// visualPromptStage schon einen nachgelagerten Wert hat, darf dieser Reparatur-Workflow
// contentStage/sharepicNeedStage/imageStage NICHT mit einer frisch aus sourceLock/
// visualAnchors abgeleiteten Einschätzung überschreiben - das würde bereits
// erzeugten Content und Sichtbarkeitsfortschritt stillschweigend zurücksetzen.
// sourceLock/visualAnchors werden trotzdem repariert (das ist der eigentliche Zweck).
function hasP1Content(row) {
  if (safeStr(row.websiteHeadline)) return true;
  const cj = safeStr(row.contentJson);
  if (!cj || cj === '{}' || cj === 'null') return false;
  try {
    const p = JSON.parse(cj);
    return p && typeof p === 'object' && !Array.isArray(p) && Object.keys(p).length > 0;
  } catch (e) {
    return false;
  }
}

const downstreamProgressed = hasP1Content(input) || !!(safeStr(input.headlineChoiceStage) || safeStr(input.visualPromptStage));

const finalSharepicNeedStage = downstreamProgressed
  ? (safeStr(input.sharepicNeedStage) || sharepicNeedStageComputed)
  : sharepicNeedStageComputed;
const finalInstagramSharepicNoetig = downstreamProgressed
  ? bool(input.instagramSharepicNoetig ?? input.instagramCarouselNoetig ?? input.visualNeeded)
  : instagramSharepicNoetig;
const finalVisualDecisionReason = downstreamProgressed
  ? (safeStr(input.visualDecisionReason) || 'Bereits weiterverarbeitet - contentStage/sharepicNeedStage durch Repair-Workflow nicht ueberschrieben.')
  : visualDecisionReason;

// analysisJson synchronisieren.
const normalizedAnalysis = {
  ...analysis,
  empfehlung,
  reaktionNoetig,
  sprengstoff,
  ampel,
  kommunikationspotenzial,
  relevanz,
  satireIntensity,
  beweissicherheit,
  rechtlichesRisiko,
  freigabeEmpfohlen,
  instagramCarouselNoetig: finalInstagramSharepicNoetig,
  sharepicNeedStage: finalSharepicNeedStage,
  sourceLock,
  visualAnchors,
  sourceLockValid,
  sourceLockErrors,
  visualAnchorsValid,
  visualAnchorsErrors: visualErrors,
  visualGuardErrors: guardErrors,
  visualDecisionReason: finalVisualDecisionReason
};

const finalImageStage = downstreamProgressed
  ? safeStr(input.imageStage)
  : (safeStr(input.imageFinalPath) ? 'composed' : 'not_started');

const finalContentStage = downstreamProgressed
  ? (input.contentStage || 'content_generated')
  : (input.contentStage || (empfehlung === 'IGNORIEREN' ? 'ignored' : 'needs_content'));
const finalContentErrorReason = safeStr(input.contentErrorReason);

const out = {
  ...input,

  analysisJson: JSON.stringify(normalizedAnalysis),

  relevantScore: relevanz,
  relevanz,
  sprengstoff,
  ampel,
  beweissicherheit,
  rechtlichesRisiko,
  kommunikationspotenzial,
  empfehlung,
  reaktionNoetig,
  freigabeEmpfohlen,
  satireIntensity,

  sourceLockValid,
  sourceLockErrors: JSON.stringify(sourceLockErrors),

  visualAnchorsValid,
  visualAnchorsErrors: JSON.stringify(visualErrors),
  visualGuardErrors: JSON.stringify(guardErrors),

  instagramCarouselNoetig: finalInstagramSharepicNoetig,
  instagramSharepicNoetig: finalInstagramSharepicNoetig,
  visualNeeded: finalInstagramSharepicNoetig,

  visualDecisionReason: finalVisualDecisionReason,
  contentStage: finalContentStage,
  contentErrorReason: finalContentErrorReason,
  sharepicNeedStage: finalSharepicNeedStage,
  imageStage: finalImageStage,
  lastAnalysisAt: new Date().toISOString(),

  // Top-Level-Spiegelung für alte Nodes / Visual Prompt Builder.
  sourceLock: JSON.stringify(sourceLock),

  satireThemaKonkret: visualAnchors.satireThemaKonkret,
  satireKonfliktKonkret: visualAnchors.satireKonfliktKonkret,
  visualPflichtobjekte: JSON.stringify(visualAnchors.visualPflichtobjekte),
  visualPflichthandlung: visualAnchors.visualPflichthandlung,
  visualBetroffene: JSON.stringify(visualAnchors.visualBetroffene),
  visualOrt: visualAnchors.visualOrt,
  visualUeberzeichnung: visualAnchors.visualUeberzeichnung,
  visualErkennungssatz: visualAnchors.visualErkennungssatz,
  visualVerboteneErsatzmotive: JSON.stringify(visualAnchors.visualVerboteneErsatzmotive)
};

return { json: out };

// Prüft, ob eine reine Guard-Blockierung (sensible Betroffene als Bildszene/Metapher in
// satireBrief/satirePunchlines/satireAngle/visualMetaphor) vorliegt, wobei sourceLock und
// visualAnchors bereits gültig sind, und ob noch kein automatischer Reparaturversuch
// stattgefunden hat (verhindert Endlosschleifen - max. 1 Versuch).

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch(e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim());
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(s => String(s).trim()); } catch(e) {}
    return v.split(/\s*\|\s*/).filter(Boolean).map(s => String(s).trim());
  }
  return [];
}
function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') { const s = v.trim().toLowerCase(); return s === 'true' || s === '1'; }
  return false;
}
function normText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
    .replace(/[„""'`´]/g, '').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
}

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { _guardRepairNeeded: false, _guardRepairSkipped: true, _guardRepairSkipReason: 'kein Input' } }];
}
const rawItem = items[0];
const j = (rawItem && rawItem.json && typeof rawItem.json === 'object' && !Array.isArray(rawItem.json)) ? rawItem.json : {};

if (!j.vorgangKey) {
  return [{ json: { ...j, _guardRepairNeeded: false, _guardRepairSkipped: true, _guardRepairSkipReason: 'kein vorgangKey' } }];
}

const analysis = parseObj(j.analysisJson);
const sl = parseObj(analysis.sourceLock || {});
const va = parseObj(analysis.visualAnchors || {});

const slOk = !!(
  safeStr(sl.sourceTopic) && safeStr(sl.sourceConflict) &&
  asArr(sl.requiredTerms).length >= 2 && asArr(sl.requiredObjects).length >= 2 &&
  safeStr(sl.requiredAction) && robustBool(analysis.sourceLockValid)
);
const vaOk = !!(
  safeStr(va.satireThemaKonkret) && safeStr(va.satireKonfliktKonkret) &&
  asArr(va.visualPflichtobjekte).length >= 2 && safeStr(va.visualPflichthandlung) &&
  safeStr(va.visualErkennungssatz) && safeStr(va.visualUeberzeichnung) &&
  asArr(va.visualVerboteneErsatzmotive).length >= 2 && robustBool(analysis.visualAnchorsValid)
);

const eignung = parseObj(j.eignungsAgentJson);
const wantsVisual = eignung.satireWorthIt === true || robustBool(j.visualNeeded) || robustBool(j.instagramSharepicNoetig);

const sourceStrictText = [
  j.title, j.vorgangsnummer, j.summaryText, j.thema, j.betroffene,
  j.kostenHaushalt, j.buergerwirkung, j.offenePunkte, j.unsicherheitenSummary, j.combinedText
].map(safeStr).join('\n');

const sensitiveContextRe = /\b(minderjaehrig|minderjährig|kind|kinder|schueler|schüler|schuelerin|schülerin|behinder|barrierefrei|barrierefreiheit|blind|sehbehindert|taub|krank|pflege|rollstuhl|gefluecht|geflücht|wohnungslose|obdachlos|armut|opfer|notlage)\b/i;
const sensitiveContext = sensitiveContextRe.test(normText(sourceStrictText + ' ' + asArr(sl.affectedGroups).join(' ')));

function isSensitivePersonObject(v) {
  const n = normText(v);
  if (!n) return false;
  if (/\b(rollstuhlrampe|rampe|barrierefreier zugang|barrierefreier taster|taster|signalgeber|bodenplatte|bodenplatten|leitstreifen|lichtsignalanlage)\b/.test(n)) return false;
  return /\b(blinder|blinde|sehbehinderter|sehbehinderte|behinderter|behinderte|mensch mit behinderung|menschen mit behinderung|schueler|schuelerin|schüler|schülerin|kind|kinder|minderjaehriger|minderjährige|patient|patientin|pflegebeduerftiger|pflegebedürftige|rollstuhlfahrer|gefluechteter|geflüchtete|wohnungslose|obdachlose|kranker|kranke)\b/.test(n);
}

function hasSensitiveMetaphor(text) {
  if (!sensitiveContext) return false;
  const n = normText(text);
  if (/\bblind(e|er|es|en)?\s+(augen|sparschwein|haushalt|verwaltung|planung|politik|ampel|stadt)\b/.test(n)) return true;
  if (/\b(taub(e|er|es|en)?|lahm(e|er|es|en)?|krank(e|er|es|en)?|hilflos(e|er|es|en)?)\s+(verwaltung|planung|haushalt|politik|ampel|stadt)\b/.test(n)) return true;
  if (/barrierefreiheit.{0,30}\b(luxus|spass|spaß|teurer spass|teurer spaß)\b/.test(n)) return true;
  if (/\b(gefahrenszene|hilflosigkeit|panik|panisch|gefährdet|gefaehrdet|unfallopfer)\b/.test(n)) return true;
  return false;
}

const visualText = [
  va.visualUeberzeichnung, va.visualErkennungssatz, analysis.visualMetaphor,
  analysis.satireBrief, analysis.satireAngle, asArr(analysis.satirePunchlines).join(' '),
  analysis.moeglicheSatirischeReaktion
].map(safeStr).join(' ');

const sensitiveObjectsFound = sensitiveContext ? [
  ...asArr(va.visualPflichtobjekte).filter(isSensitivePersonObject),
  ...asArr(sl.requiredObjects).filter(isSensitivePersonObject)
] : [];

const guardBlocked = sensitiveObjectsFound.length > 0 || hasSensitiveMetaphor(visualText);

const alreadyAttempted = robustBool(analysis._guardRepairAttempted || j._guardRepairAttempted);

const guardRepairNeeded = wantsVisual && slOk && vaOk && guardBlocked && !alreadyAttempted;

const guardBlockedReasons = [
  ...sensitiveObjectsFound.map(o => 'Sensible Betroffene als Bildobjekt: ' + o),
  ...(hasSensitiveMetaphor(visualText) ? ['Sensible Betroffene erscheinen in Visual- oder Satirefeldern als Bildszene/Pointe'] : [])
].join(' | ');

return [{ json: {
  ...j,
  _guardRepairNeeded: guardRepairNeeded,
  _guardRepairSkipped: false,
  _guardBlockedReasons: guardBlockedReasons,
  _guardAlreadyAttempted: alreadyAttempted,
  satireTarget: j.satireTarget || analysis.satireTarget || ''
} }];

