parameters.jsCode:
// Übernimmt die von "AI Reparatur Visual Guard" überarbeiteten Satire-/Bildfelder,
// prüft den Guard erneut (identische Logik wie "Parse Reparatur JSON" / "Prüfe Guard-Repair-Bedarf")
// und setzt sharepicNeedStage final. Max. 1 automatischer Versuch (_guardRepairAttempted verhindert Endlosschleife).

function getAiText(item) {
  try {
    const j = item.json || {};
    if (j.text && typeof j.text === 'string' && j.text.trim()) return j.text;
    const o = j.output;
    if (Array.isArray(o)) {
      for (let i = 0; i < o.length; i++) {
        const c = o[i].content;
        if (Array.isArray(c)) { for (let k = 0; k < c.length; k++) { if (c[k].text) return c[k].text; } }
      }
    }
    if (j.output_text) return j.output_text;
    if (j.message && j.message.content) return j.message.content;
    if (j.choices && j.choices[0] && j.choices[0].message) return j.choices[0].message.content || '';
    return '';
  } catch (e) { return ''; }
}
function extractJson(text) {
  if (!text) return null;
  const s = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const a = s.indexOf('{'), b = s.lastIndexOf('}');
  return (a === -1 || b === -1 || b <= a) ? null : s.slice(a, b + 1);
}
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  if (typeof v === 'string') { try { const p = JSON.parse(v); return p && typeof p === 'object' && !Array.isArray(p) ? p : {}; } catch (e) {} }
  return {};
}
function asArray(v) {
  if (Array.isArray(v)) return v.filter(x => x !== null && x !== undefined && safeStr(x) !== '').map(x => safeStr(x));
  if (v === null || v === undefined || v === '') return [];
  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return [];
    try { const p = JSON.parse(t); if (Array.isArray(p)) return p.filter(Boolean).map(x => safeStr(x)).filter(Boolean); } catch (e) {}
    return t.split(/\s*\|\s*/).map(x => safeStr(x)).filter(Boolean);
  }
  return [safeStr(v)].filter(Boolean);
}
function normText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
    .replace(/[„""'`´]/g, '').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
}

let input = {};
try {
  const ref = $('Prüfe Guard-Repair-Bedarf').item;
  if (ref && ref.json && typeof ref.json === 'object' && !Array.isArray(ref.json)) input = ref.json;
} catch (e) { input = {}; }

const rawAiText = getAiText($input.item);
const aiJsonStr = extractJson(rawAiText);
let repaired = {};
if (aiJsonStr) { try { repaired = JSON.parse(aiJsonStr) || {}; } catch (e) { repaired = {}; } }

const analysis = parseObj(input.analysisJson);
const sl = parseObj(analysis.sourceLock || {});
const va = parseObj(analysis.visualAnchors || {});

// Überarbeitete Felder übernehmen, alles andere unverändert lassen.
const satireBrief = safeStr(repaired.satireBrief) || safeStr(analysis.satireBrief || input.satireBrief);
const satirePunchlines = asArray(repaired.satirePunchlines).length ? asArray(repaired.satirePunchlines) : asArray(analysis.satirePunchlines || input.satirePunchlines);
const satireAngle = safeStr(repaired.satireAngle) || safeStr(analysis.satireAngle || input.satireAngle);
const visualMetaphor = safeStr(repaired.visualMetaphor) || safeStr(analysis.visualMetaphor || input.visualMetaphor);
va.visualUeberzeichnung = safeStr(repaired.visualUeberzeichnung) || safeStr(va.visualUeberzeichnung);
va.visualErkennungssatz = safeStr(repaired.visualErkennungssatz) || safeStr(va.visualErkennungssatz);
va.visualPflichthandlung = safeStr(repaired.visualPflichthandlung) || safeStr(va.visualPflichthandlung);

analysis.satireBrief = satireBrief;
analysis.satirePunchlines = satirePunchlines;
analysis.satireAngle = satireAngle;
analysis.visualMetaphor = visualMetaphor;
analysis.visualAnchors = va;

// Guard erneut prüfen (identische Logik wie in "Parse Reparatur JSON").
const sourceStrictText = [
  input.title, input.vorgangsnummer, input.summaryText, input.thema, input.betroffene,
  input.kostenHaushalt, input.buergerwirkung, input.offenePunkte, input.unsicherheitenSummary, input.combinedText
].map(safeStr).join('\n');

const sensitiveContextRe = /\b(minderjaehrig|minderjährig|kind|kinder|schueler|schüler|schuelerin|schülerin|behinder|barrierefrei|barrierefreiheit|blind|sehbehindert|taub|krank|pflege|rollstuhl|gefluecht|geflücht|wohnungslose|obdachlos|armut|opfer|notlage)\b/i;
const sensitiveContext = sensitiveContextRe.test(normText(sourceStrictText + ' ' + asArray(sl.affectedGroups).join(' ')));

function isSensitivePersonObject(v) {
  const n = normText(v);
  if (!n) return false;
  if (/\b(rollstuhlrampe|rampe|barrierefreier zugang|barrierefreier taster|taster|signalgeber|bodenplatte|bodenplatten|leitstreifen|lichtsignalanlage)\b/.test(n)) return false;
  return /\b(blinder|blinde|sehbehinderter|sehbehinderte|behinderter|behinderte|mensch mit behinderung|menschen mit behinderung|schueler|schuelerin|schüler|schülerin|kind|kinder|minderjaehriger|minderjährige|patient|patientin|pflegebeduerftiger|pflegebedürftige|rollstuhlfahrer|gefluechteter|geflüchtete|wohnungslose|obdachlose|kranker|kranke)\b/.test(n);
}
function hasSensitiveMetaphor(text) {
  if (!sensitiveContext) return false;
  const n = normText(text);
  if (/\bblind(e|er|es|en)?\s+(augen|sparschwein|haushalt|verwaltung|planung|politik|ampel|stadt)\b/.test(n)) return true;
  if (/\b(taub(e|er|es|en)?|lahm(e|er|es|en)?|krank(e|er|es|en)?|hilflos(e|er|es|en)?)\s+(verwaltung|planung|haushalt|politik|ampel|stadt)\b/.test(n)) return true;
  if (/barrierefreiheit.{0,30}\b(luxus|spass|spaß|teurer spass|teurer spaß)\b/.test(n)) return true;
  if (/\b(gefahrenszene|hilflosigkeit|panik|panisch|gefährdet|gefaehrdet|unfallopfer)\b/.test(n)) return true;
  return false;
}

const visualText = [
  va.visualUeberzeichnung, va.visualErkennungssatz, visualMetaphor, satireBrief, satireAngle,
  satirePunchlines.join(' '), analysis.moeglicheSatirischeReaktion
].map(safeStr).join(' ');

const sensitiveObjectsFound = sensitiveContext ? [
  ...asArray(va.visualPflichtobjekte).filter(isSensitivePersonObject),
  ...asArray(sl.requiredObjects).filter(isSensitivePersonObject)
] : [];

const stillBlocked = sensitiveObjectsFound.length > 0 || hasSensitiveMetaphor(visualText);

let sharepicNeedStageComputed, instagramSharepicNoetig, visualDecisionReason;
if (!stillBlocked) {
  sharepicNeedStageComputed = 'topic_ok';
  instagramSharepicNoetig = true;
  visualDecisionReason = 'Sharepic freigegeben nach automatischer Entschärfung (sensible Betroffene aus Bildmotiv entfernt).';
} else {
  sharepicNeedStageComputed = 'topic_error';
  instagramSharepicNoetig = false;
  visualDecisionReason = 'Sharepic weiterhin blockiert auch nach automatischer Entschärfung: ' +
    [
      ...sensitiveObjectsFound.map(o => 'Sensible Betroffene als Bildobjekt: ' + o),
      ...(hasSensitiveMetaphor(visualText) ? ['Sensible Betroffene erscheinen weiterhin als Bildszene/Pointe'] : [])
    ].join(' | ');
}

// Wenn P1 bereits contentJson/websiteHeadline erzeugt hat oder headlineChoiceStage/
// visualPromptStage schon einen nachgelagerten Wert hat, darf dieser Guard-Reparatur-Schritt
// contentStage/sharepicNeedStage nicht mit der frisch berechneten Einschätzung überschreiben -
// sonst wird bereits erzeugter Content/Sichtbarkeitsfortschritt zurückgesetzt.
function hasP1Content(row) {
  if (safeStr(row.websiteHeadline)) return true;
  const cj = safeStr(row.contentJson);
  if (!cj || cj === '{}' || cj === 'null') return false;
  try {
    const p = JSON.parse(cj);
    return p && typeof p === 'object' && !Array.isArray(p) && Object.keys(p).length > 0;
  } catch (e) {
    return false;
  }
}

const downstreamProgressed = hasP1Content(input) || !!(safeStr(input.headlineChoiceStage) || safeStr(input.visualPromptStage));

const finalSharepicNeedStage = downstreamProgressed ? (safeStr(input.sharepicNeedStage) || sharepicNeedStageComputed) : sharepicNeedStageComputed;
const finalInstagramSharepicNoetig = downstreamProgressed
  ? (input.instagramSharepicNoetig === true || input.instagramCarouselNoetig === true || input.visualNeeded === true)
  : instagramSharepicNoetig;
const finalVisualDecisionReason = downstreamProgressed
  ? (safeStr(input.visualDecisionReason) || 'Bereits weiterverarbeitet - contentStage/sharepicNeedStage durch Guard-Reparatur nicht ueberschrieben.')
  : visualDecisionReason;

analysis._guardRepairAttempted = true;

const finalContentStage = downstreamProgressed ? (input.contentStage || 'content_generated') : (input.contentStage || 'needs_content');
const finalContentErrorReason = safeStr(input.contentErrorReason);
const finalImageStage = downstreamProgressed ? safeStr(input.imageStage) : (safeStr(input.imageFinalPath) ? 'composed' : 'not_started');

const out = {
  ...input,
  analysisJson: JSON.stringify(analysis),
  sharepicNeedStage: finalSharepicNeedStage,
  imageStage: finalImageStage,
  instagramSharepicNoetig: finalInstagramSharepicNoetig,
  visualNeeded: finalInstagramSharepicNoetig,
  instagramCarouselNoetig: finalInstagramSharepicNoetig,
  visualDecisionReason: finalVisualDecisionReason,
  contentStage: finalContentStage,
  contentErrorReason: finalContentErrorReason,
  lastAnalysisAt: new Date().toISOString(),
  satireBrief,
  satirePunchlines: JSON.stringify(satirePunchlines),
  satireAngle,
  visualMetaphor,
  visualUeberzeichnung: va.visualUeberzeichnung,
  visualErkennungssatz: va.visualErkennungssatz,
  visualPflichthandlung: va.visualPflichthandlung,
  _guardRepairAttempted: true
};

return { json: out };
